+    if (builtin.os.tag == .wasi) {
+        return qjs.JS_NewString(ctx, "WASI");
+    }
+
+    var uname_buf: std.c.utsname = undefined;
+    if (std.c.uname(&uname_buf) == 0) {
+        return qjs.JS_NewString(ctx, &uname_buf.version);
+    }
+
+    return qjs.JS_NewString(ctx, "unknown");
+}
